import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Assume the function is exported from './notes'
import { sortNotesByUpdatedAt } from './notes';

describe('sortNotesByUpdatedAt', () => {
  it('should handle happy path - sorts notes by updatedAt descending', () => {
    const notes = [
      { id: 1, updatedAt: new Date('2023-01-01T10:00:00Z') },
      { id: 2, updatedAt: new Date('2023-02-01T10:00:00Z') },
      { id: 3, updatedAt: new Date('2023-01-15T10:00:00Z') },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    expect(sorted[0].id).toBe(2);
    expect(sorted[1].id).toBe(3);
    expect(sorted[2].id).toBe(1);
  });

  it('should handle edge case - notes with identical timestamps remain in original order', () => {
    const notes = [
      { id: 1, updatedAt: new Date('2023-01-01T10:00:00Z') },
      { id: 2, updatedAt: new Date('2023-01-01T10:00:00Z') },
      { id: 3, updatedAt: new Date('2023-02-01T10:00:00Z') },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    // Note with later timestamp first
    expect(sorted[0].id).toBe(3);
    // The two with same timestamp should preserve original relative order
    expect(sorted[1].id).toBe(1);
    expect(sorted[2].id).toBe(2);
  });

  it('should handle null/empty inputs - returns empty array for null, undefined, empty string, or 0', () => {
    const inputs: any[] = [null, undefined, '', 0];

    inputs.forEach((input) => {
      const result = sortNotesByUpdatedAt(input);
      expect(Array.isArray(result)).toBe(true);
      expect(result.length).toBe(0);
    });
  });
});

