import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { countWords } from './path/to/your/module';

describe('countWords', () => {
  it('should handle happy path with a normal sentence', () => {
    const text = 'The quick brown fox jumps over the lazy dog';
    const result = countWords(text);
    expect(result).toBe(9);
  });

  it('should handle edge case with multiple spaces and punctuation', () => {
    const text = 'Hello,,   world!   This   is   a-test.';
    const result = countWords(text);
    // Words: "Hello", "world", "This", "is", "a-test" -> 5 words
    expect(result).toBe(5);
  });

  it('should handle null/empty inputs', () => {
    expect(countWords(null as any)).toBe(0);
    expect(countWords(undefined as any)).toBe(0);
    expect(countWords('')).toBe(0);
    expect(countWords('   ')).toBe(0);
  });
});